#!/usr/bin/env node
// Drift check for the committed command-reference pages (issue #74,
// ADR-0008). Reads a `gohealthcli schema --json` document from stdin, runs
// the existing generator (gen-command-reference.mjs) against a temporary
// directory, and compares the regenerated bytes against the committed
// docs/commands.md and docs/commands/*.md. Exits non-zero on any mismatch,
// printing a unified diff that identifies the drifted file.
//
// Invoked by `make docs-check`; the fix for a failure is always
// `make docs-commands` plus committing the result (or reverting the
// hand-edit that caused the drift).
import fs from "node:fs";
import os from "node:os";
import path from "node:path";
import { spawnSync } from "node:child_process";
import { fileURLToPath } from "node:url";
import { PRESERVED_DOC_FILES } from "./gen-command-reference.mjs";

const scriptDir = path.dirname(fileURLToPath(import.meta.url));
const repoRoot = path.dirname(scriptDir);
const generatorPath = path.join(scriptDir, "gen-command-reference.mjs");

async function main() {
  const chunks = [];
  for await (const chunk of process.stdin) chunks.push(chunk);
  const schemaJSON = Buffer.concat(chunks);
  if (!schemaJSON.length) {
    console.error("check-command-reference: no schema JSON on stdin");
    process.exit(1);
  }

  const tmpRoot = fs.mkdtempSync(path.join(os.tmpdir(), "docs-check-"));
  try {
    // Reuse the committed generator end-to-end: it writes docs/commands.md
    // and docs/commands/*.md relative to its cwd, so pointing cwd at a temp
    // directory yields a pristine regeneration without touching the repo.
    const gen = spawnSync(process.execPath, [generatorPath], {
      cwd: tmpRoot,
      input: schemaJSON,
      encoding: "utf8",
    });
    if (gen.status !== 0) {
      console.error("check-command-reference: generator failed");
      if (gen.stderr) console.error(gen.stderr.trimEnd());
      process.exit(1);
    }

    const drifted = compareTrees(repoRoot, tmpRoot);
    if (drifted.length) {
      console.error("");
      console.error(`check-command-reference: ${drifted.length} file${drifted.length === 1 ? "" : "s"} drifted from a fresh \`schema --json\` regeneration:`);
      for (const name of drifted) console.error(`  ${name}`);
      console.error("run `make docs-commands` and commit the result.");
      process.exit(1);
    }
    console.log("docs-check: committed command-reference pages match a fresh regeneration");
  } finally {
    fs.rmSync(tmpRoot, { recursive: true, force: true });
  }
}

// compareTrees byte-compares the committed command-reference files against
// the regenerated ones and returns the repo-relative paths that drifted.
// Hand-written pages in PRESERVED_DOC_FILES are never regenerated, so they
// are excluded from the comparison.
function compareTrees(committedRoot, regeneratedRoot) {
  const drifted = [];
  compareFile(committedRoot, regeneratedRoot, path.join("docs", "commands.md"), drifted);

  const committed = listMarkdown(path.join(committedRoot, "docs", "commands"));
  const regenerated = listMarkdown(path.join(regeneratedRoot, "docs", "commands"));

  for (const name of regenerated) {
    compareFile(committedRoot, regeneratedRoot, path.join("docs", "commands", name), drifted);
  }
  for (const name of committed) {
    if (PRESERVED_DOC_FILES.has(name)) continue;
    if (regenerated.includes(name)) continue;
    const rel = path.join("docs", "commands", name);
    console.error(`drift: ${rel} is committed but a fresh regeneration no longer produces it (stale page)`);
    drifted.push(rel);
  }
  return drifted.sort();
}

// listMarkdown returns the sorted *.md file names directly under dir
// (no recursion — the generator only writes flat pages). An absent dir
// yields an empty list so a missing docs/commands/ reads as "everything
// drifted" rather than a crash.
function listMarkdown(dir) {
  if (!fs.existsSync(dir)) return [];
  return fs
    .readdirSync(dir, { withFileTypes: true })
    .filter((e) => e.isFile() && e.name.endsWith(".md"))
    .map((e) => e.name)
    .sort();
}

// compareFile byte-compares one repo-relative file across the two roots.
// On mismatch it prints a heading naming the file plus a unified diff and
// appends the path to drifted. Returns true when the bytes match.
function compareFile(committedRoot, regeneratedRoot, rel, drifted) {
  const committedPath = path.join(committedRoot, rel);
  const regeneratedPath = path.join(regeneratedRoot, rel);
  if (!fs.existsSync(committedPath)) {
    console.error(`drift: ${rel} is missing from the repository but a fresh regeneration produces it`);
    drifted.push(rel);
    return false;
  }
  const committedBytes = fs.readFileSync(committedPath);
  const regeneratedBytes = fs.readFileSync(regeneratedPath);
  if (committedBytes.equals(regeneratedBytes)) return true;

  console.error(`drift: ${rel} differs from a fresh regeneration`);
  printUnifiedDiff(committedPath, regeneratedPath, rel);
  drifted.push(rel);
  return false;
}

// printUnifiedDiff shells out to the system `diff -u` (present on the
// Ubuntu CI runners and macOS dev machines). Labels replace the temp-dir
// paths so the diff itself identifies the repo file. Falls back to a plain
// notice when `diff` is unavailable — the heading printed by compareFile
// already names the file.
function printUnifiedDiff(committedPath, regeneratedPath, rel) {
  const diff = spawnSync(
    "diff",
    ["-u", "-L", `${rel} (committed)`, "-L", `${rel} (regenerated)`, committedPath, regeneratedPath],
    { encoding: "utf8" },
  );
  if (diff.error) {
    console.error("  (diff unavailable: install diffutils for a line-level diff)");
    return;
  }
  if (diff.stdout) console.error(diff.stdout.trimEnd());
}

await main();
